async function saveRequestFiles (options) {
  // Checks if this has already been run
  if (this[kSavedRequestFilesResult]) {
    return this[kSavedRequestFilesResult]
  }

  let parts
  let values = {}

  if (attachFieldsToBody === true || attachFieldsToBody === 'keyValues') {
    parts = this.body ? filesFromFields.call(this, this.body) : []
    values = this.body || {}
  } else {
    parts = this.parts(options)
  }

  this.savedRequestFiles = []
  const tmpdir = options?.tmpdir || os.tmpdir()
  this.tmpUploads = []
  let i = 0
  for await (const part of parts) {
    values = part.fields

    if (!part.file) {
      continue
    }

    const filepath = path.join(tmpdir, generateId() + path.extname(part.filename || ('file' + i++)))
    const target = createWriteStream(filepath)
    try {
      this.tmpUploads.push(filepath)
      await pump(part.file, target)
      this.savedRequestFiles.push({ ...part, filepath })
    } catch (err) {
      target.destroy()
      await this.cleanRequestFiles()
      this.log.error({ err }, 'save request file')
      throw err
    }
  }

  this[kSavedRequestFilesResult] = {
    files: this.savedRequestFiles,
    values
  }

  return this[kSavedRequestFilesResult]
}

gracefulShutdownPlugin: FastifyPluginAsync<GracefulShutdownOptions> =
  async function gracefulShutdownPlugin(fastify, userOptions = {}) {
    const logger = fastify.log.child({
      plugin: 'fastify-micro:graceful-shutdown'
    })

    const options = {
      ...defaultGracefulShutdownOptions,
      ...userOptions
    }

    options.signals.forEach(signal => {
      process.once(signal, () => {
        const tick = performance.now()
        logger.info({ signal }, 'Received signal')
        const timeout = setTimeout(() => {
          logger.fatal({ signal }, 'Hard-exiting the process after timeout')
          process.exit(options.hardExitCode)
        }, options.timeoutMs)
        fastify.close().then(
          () => {
            const tock = performance.now()
            clearTimeout(timeout)
            logger.info(
              { signal, onCloseDuration: tock - tick },
              'Process terminated in time. Bye!'
            )
            process.exit(0)
          },
          error => {
            const tock = performance.now()
            logger.error(
              { signal, error, onCloseDuration: tock - tick },
              'Process terminated with error in `onClose` hook'
            )
            process.exit(1)
          }
        )
      })
    })
  }

function buildSchemaController (parentSchemaCtrl, opts) {
  if (parentSchemaCtrl) {
    return new SchemaController(parentSchemaCtrl, opts)
  }

  const compilersFactory = Object.assign({
    buildValidator: null,
    buildSerializer: null
  }, opts?.compilersFactory)

  if (!compilersFactory.buildValidator) {
    const ValidatorSelector = require('@fastify/ajv-compiler')
    compilersFactory.buildValidator = ValidatorSelector()
  }
  if (!compilersFactory.buildSerializer) {
    const SerializerSelector = require('@fastify/fast-json-stringify-compiler')
    compilersFactory.buildSerializer = SerializerSelector()
  }

  const option = {
    bucket: (opts && opts.bucket) || buildSchemas,
    compilersFactory,
    isCustomValidatorCompiler: typeof opts?.compilersFactory?.buildValidator === 'function',
    isCustomSerializerCompiler: typeof opts?.compilersFactory?.buildSerializer === 'function'
  }

  return new SchemaController(undefined, option)
}

export function createRequest<Server extends HttpServer>(
  request: FastifyRequest<RouteGenericInterface, Server>,
  reply: FastifyReply<RouteGenericInterface, Server>,
  createReadableStreamFromReadable:
    | typeof RemixCreateReadableStreamFromReadable
    | typeof RRCreateReadableStreamFromReadable,
): Request {
  let url = getUrl(request);

  let controller: AbortController | null = new AbortController();

  let init: RequestInit = {
    method: request.method,
    headers: createHeaders(request.headers),
    signal: controller.signal,
  };

  // Abort action/loaders once we can no longer write a response if we have
  // not yet sent a response (i.e., `close` without `finish`)
  // `finish` -> done rendering the response
  // `close` -> response can no longer be written to
  reply.raw.on("finish", () => (controller = null));
  reply.raw.on("close", () => controller?.abort());

  if (request.method !== "GET" && request.method !== "HEAD") {
    init.body = createReadableStreamFromReadable(request.raw);
    init.duplex = "half";
  }

  return new Request(url, init);
}

Boot.prototype._addPlugin = function (pluginFn, opts, isAfter) {
  if (isBundledOrTypescriptPlugin(pluginFn)) {
    pluginFn = pluginFn.default
  }
  validatePlugin(pluginFn)
  opts = opts || {}

  if (this.booted) {
    throw new AVV_ERR_ROOT_PLG_BOOTED()
  }

  // we always add plugins to load at the current element
  const current = this._current[0]

  let timeout = this._opts.timeout

  if (!current.loaded && current.timeout > 0) {
    const delta = Date.now() - current.startTime
    // We need to decrease it by 3ms to make sure the internal timeout
    // is triggered earlier than the parent
    timeout = current.timeout - (delta + 3)
  }

  const plugin = new Plugin(fastq(this, this._loadPluginNextTick, 1), pluginFn, opts, isAfter, timeout)
  this._trackPluginLoading(plugin)

  if (current.loaded) {
    throw new Error(plugin.name, current.name)
  }

  // we add the plugin to be loaded at the end of the current queue
  current.enqueue(plugin, (err) => { err && (this._error = err) })

  return plugin
}

Boot.prototype._loadPlugin = function (plugin, callback) {
  const instance = this
  if (isPromiseLike(plugin.func)) {
    plugin.func.then((fn) => {
      if (typeof fn.default === 'function') {
        fn = fn.default
      }
      plugin.func = fn
      this._loadPlugin(plugin, callback)
    }, callback)
    return
  }

  const last = instance._current[0]

  // place the plugin at the top of _current
  instance._current.unshift(plugin)

  if (instance._error && !plugin.isAfter) {
    debug('skipping loading of plugin as instance errored and it is not an after', plugin.name)
    process.nextTick(execCallback)
    return
  }

  let server = last?.server || instance._server

  if (!plugin.isAfter) {
    // Skip override for after
    try {
      server = instance.override(server, plugin.func, plugin.options)
    } catch (overrideErr) {
      debug('override errored', plugin.name)
      return execCallback(overrideErr)
    }
  }

  plugin.exec(server, execCallback)

  function execCallback (err) {
    plugin.finish(err, (err) => {
      instance._current.shift()
      callback(err)
    })
  }
}

async function requireServerPluginFromPath (modulePath) {
  const resolvedModulePath = path.resolve(process.cwd(), modulePath)

  if (!fs.existsSync(resolvedModulePath)) {
    throw new Error(`${resolvedModulePath} doesn't exist within ${process.cwd()}`)
  }

  const packageType = await getPackageType(resolvedModulePath)
  const type = getScriptType(resolvedModulePath, packageType)

  let serverPlugin
  if (type === 'module') {
    if (moduleSupport) {
      serverPlugin = await import(url.pathToFileURL(resolvedModulePath).href)
    } else {
      throw new Error(`fastify-cli cannot import plugin at '${resolvedModulePath}'. Your version of node does not support ES modules. To fix this error upgrade to Node 14 or use CommonJS syntax.`)
    }
  } else {
    serverPlugin = require(resolvedModulePath)
  }

  if (isInvalidAsyncPlugin(type === 'commonjs' ? serverPlugin : serverPlugin.default)) {
    throw new Error('Async/Await plugin function should contain 2 arguments. ' +
      'Refer to documentation for more information.')
  }

  return serverPlugin
}

function cli (args) {
  const opts = parseArgs(args, {
    options: {
      help: { type: 'boolean' }
    }
  })

  const dir = process.cwd()

  if (opts._.length !== 1) {
    log('error', 'Missing the required file parameter\n')
    return showHelp()
  }

  if (existsSync(path.join(dir, 'README.md'))) {
    log('error', 'a README.md file already exists in target directory')
    process.exit(1)
  }

  const pluginPath = path.join(dir, path.basename(opts._[0], '.js'))

  let plugin
  try {
    plugin = require(pluginPath)
  } catch (err) {
    log('error', 'plugin could not be loaded', err)
    process.exit(1)
  }

  const pluginMeta = plugin[Symbol.for('plugin-meta')]

  if (!pluginMeta) {
    log('error', 'no plugin metadata could be found. Are you sure that you use https://github.com/fastify/fastify-plugin ?')
    process.exit(1)
  }

  const encapsulated = !plugin[Symbol.for('skip-override')]
  const pluginFileName = path.basename(opts._[0])

  generate(dir, { pluginMeta, encapsulated, pluginFileName }).catch(function (err) {
    if (err) {
      log('error', err.message)
      process.exit(1)
    }
  })
}

async function viewHandlebars (page, data, opts) {
  if (opts?.layout) {
    layoutIsValid(opts.layout)
    return withLayout(viewHandlebars, opts.layout).call(this, page, data)
  }

  let options

  if (globalOptions.useDataVariables) {
    options = {
      data: defaultCtx ? Object.assign({}, defaultCtx, this.locals) : this.locals
    }
  } else {
    data = Object.assign({}, defaultCtx, this.locals, data)
  }

  if (typeof page === 'string') {
    // append view extension
    page = getPage(page, 'hbs')
  }
  const requestedPath = getRequestedPath(this)
  const template = await getTemplate(page)

  if (prod) {
    return template(data, options)
  } else {
    const partialsObject = await getPartials(type, { partials: globalOptions.partials || {}, requestedPath })

    Object.keys(partialsObject).forEach((name) => {
      engine.registerPartial(name, engine.compile(partialsObject[name], globalOptions.compileOptions))
    })

    return template(data, options)
  }
}

async inject (id, injectParams) {
  // Make sure the application exists
  await this.#getApplicationById(id, true)

  if (typeof injectParams === 'string') {
    injectParams = { url: injectParams }
  }

  let { method, headers, body } = injectParams
  const url = new URL(injectParams.url, `http://${id}.plt.local`)

  if (injectParams.query) {
    for (const [k, v] of Object.entries(injectParams.query)) {
      url.searchParams.append(k, v)
    }
  }

  // Stringify the body as JSON if needed
  if (
    body &&
    typeof body === 'object' &&
    headers &&
    Object.entries(headers).some(([k, v]) => k.toLowerCase() === 'content-type' && v.includes('application/json'))
  ) {
    body = JSON.stringify(body)
  }

  const {
    statusCode: responseStatus,
    headers: responseHeaders,
    body: responseRawBody
  } = await request(url.toString(), { method, headers, body, dispatcher: this.#dispatcher })
  const responsePayload = await responseRawBody.arrayBuffer()
  const responseBody = Buffer.from(responsePayload).toString('utf-8')

  return {
    statusCode: responseStatus,
    statusMessage: STATUS_CODES[responseStatus] || 'unknown',
    headers: responseHeaders,
    body: responseBody,
    payload: responseBody,
    rawPayload: responsePayload
  }
}

function generate (dir, template) {
  return new Promise((resolve, reject) => {
    generify(path.join(__dirname, 'templates', template.dir), dir, {}, function (file) {
      log('debug', `generated ${file}`)
    }, function (err) {
      if (err) {
        return reject(err)
      }

      process.chdir(dir)
      execSync('npm init -y')

      log('info', `reading package.json in ${dir}`)
      readFile('package.json', (err, data) => {
        if (err) {
          return reject(err)
        }

        let pkg
        try {
          pkg = JSON.parse(data)
        } catch (err) {
          return reject(err)
        }

        pkg.main = template.main

        pkg.type = template.type

        pkg.scripts = Object.assign(pkg.scripts || {}, template.scripts)

        pkg.dependencies = Object.assign(pkg.dependencies || {}, template.dependencies)

        pkg.devDependencies = Object.assign(pkg.devDependencies || {}, template.devDependencies)

        log('debug', 'edited package.json, saving')
        writeFile('package.json', JSON.stringify(pkg, null, 2), (err) => {
          if (err) {
            return reject(err)
          }

          template.logInstructions(pkg)
          resolve()
        })
      })
    })
  })
}

let externalsHealthy = false
  let externalHealthCheckTimer
  if (healthCheck) {
    assert(typeof healthCheck === 'function', 'opts.healthCheck should be a function that returns a promise that resolves to true or false')
    assert(healthCheckInterval > 0 || opts.exposeStatusRoute, 'opts.healthCheck requires opts.healthCheckInterval or opts.exposeStatusRoute')

    const doCheck = async () => {
      try {
        externalsHealthy = await healthCheck(fastify)
      } catch (error) {
        externalsHealthy = false
        fastify.log.error({ error }, 'external healthCheck function supplied to `under-pressure` threw an error. setting the service status to unhealthy.')
      }
    }

    await doCheck()

    if (healthCheckInterval > 0) {
      const beginCheck = async () => {
        await doCheck()
        externalHealthCheckTimer.refresh()
      }

      externalHealthCheckTimer = setTimeout(beginCheck, healthCheckInterval)
      externalHealthCheckTimer.unref()
    }
  } else {
    externalsHealthy = true
  }

async restartApplication (id) {
  const applicationConfig = this.#applications.get(id)

  if (!applicationConfig) {
    throw new ApplicationNotFoundError(id, this.getApplicationsIds().join(', '))
  }

  if (this.#restartingApplications.has(id)) {
    return
  }

  // Wait for the runtime to be fully started before attempting a restart.
  // Restarting an application while the runtime is still starting causes
  // races between the start and stop ITC commands in the worker thread.
  if (this.#status === 'starting') {
    await once(this, 'started')
  }

  this.#restartingApplications.add(id)

  try {
    const config = this.#config
    const workersIds = await this.#workers.getKeys(id)
    const workersCount = workersIds.length

    this.emitAndNotify('application:restarting', id)

    for (let i = 0; i < workersCount; i++) {
      const workerId = workersIds[i]
      const worker = this.#workers.get(workerId)

      if (i > 0 && config.workersRestartDelay > 0) {
        await sleep(config.workersRestartDelay)
      }

      await this.#replaceWorker(config, applicationConfig, workersCount, id, i, worker, true)
    }

    this.#incrementApplicationRestartCount(id)
    this.emitAndNotify('application:restarted', id)
  } finally {
    this.#restartingApplications.delete(id)
  }
}

