function prepareOpenapiObject (opts) {
  const pkg = readPackageJson()
  const openapiObject = {
    openapi: '3.0.3',
    info: {
      version: pkg.version || '1.0.0',
      title: pkg.name || ''
    },
    components: { schemas: {} },
    paths: {}
  }

  if (opts.openapi) openapiObject.openapi = opts.openapi
  if (opts.info) openapiObject.info = opts.info
  if (opts.servers) openapiObject.servers = opts.servers
  if (opts.components) openapiObject.components = Object.assign({}, opts.components, { schemas: Object.assign({}, opts.components.schemas) })
  if (opts.paths) openapiObject.paths = opts.paths
  if (opts.webhooks) openapiObject.webhooks = opts.webhooks
  if (opts.security) openapiObject.security = opts.security
  if (opts.tags) openapiObject.tags = opts.tags
  if (opts.externalDocs) openapiObject.externalDocs = opts.externalDocs

  for (const [key, value] of opts.extensions) {
    // "x-" extension can not be typed
    openapiObject[key] = value
  }

  return openapiObject
}

export default function Form() {
  // useServerAction(endpoint) acts a React suspense resource,
  // with the exception that data is retrieved only once per
  // route and cleared only when the user navigates to another route.
  const data = useServerAction(accessCounter)
  const [counter, setCounter] = useState(data.counter)

  // Just use endpoint string to retrieve fresh data on-demand
  const incrementCounter = async () => {
    const request = await fetch(accessCounter)
    const data = await request.json(0)
    setCounter(data.counter)
  }

  return (
    <>
      <h1>Using inline server GET handler</h1>
      <p>
        <code>useServerAction(endpoint)</code> acts a React Suspense resource, with the exception
        that data is retrieved only once per route and cleared only when the user navigates to
        another route.
      </p>
      <p>Counter: {counter}</p>
      <input type="button" value="Increment" onClick={incrementCounter} />
      <p>
        <Link to="/">Go back to the index</Link>
      </p>
    </>
  )
}

