async function helmetPlugin(fastify: FastifyInstance) {
  await fastify.register(helmet, {
    crossOriginResourcePolicy: { policy: 'same-origin' },
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
        scriptSrc: ["'self'", "'unsafe-inline'"], // Needed for Swagger UI and Vite
        styleSrc: ["'self'", "'unsafe-inline'"], // Needed for inline styles
        imgSrc: ["'self'", 'data:', 'blob:'], // Allow data URIs for images
        fontSrc: ["'self'"],
        connectSrc: ["'self'", 'http://localhost:3001'], // For API calls and SSE
        objectSrc: ["'none'"],
        frameSrc: ["'none'"],
        baseUri: ["'self'"],
        formAction: ["'self'"],
        frameAncestors: ["'none'"], // Prevent clickjacking
        upgradeInsecureRequests: null // Disable for local HTTP development
      }
    },
    crossOriginOpenerPolicy: { policy: 'same-origin' },
    originAgentCluster: true,
    referrerPolicy: { policy: 'strict-origin-when-cross-origin' },
    xContentTypeOptions: true,
    xDnsPrefetchControl: { allow: false },
    xDownloadOptions: true,
    xFrameOptions: { action: 'deny' },
    xPermittedCrossDomainPolicies: { permittedPolicies: 'none' },
    xXssProtection: true
  });
}

export function fastifyApollo<
	Context extends BaseContext = BaseContext,
	RawServer extends RawServerBase = RawServerDefault,
	TypeProvider extends FastifyTypeProvider = FastifyTypeProviderDefault,
>(
	apollo: ApolloServer<Context>,
): FastifyPluginAsync<
	WithRequired<ApolloFastifyPluginOptions<Context, RawServer>, "context">,
	RawServer,
	TypeProvider,
	FastifyBaseLogger
> {
	if (apollo === undefined || apollo === null || !isApolloServerLike(apollo)) {
		throw new TypeError("You must pass in an instance of `ApolloServer`.");
	}

	apollo.assertStarted("fastifyApollo()");

	return fastifyPlugin<
		WithRequired<ApolloFastifyPluginOptions<Context, RawServer>, "context">,
		RawServer,
		TypeProvider,
		FastifyBaseLogger,
		FastifyPluginAsync<
			WithRequired<ApolloFastifyPluginOptions<Context, RawServer>, "context">,
			RawServer,
			TypeProvider,
			FastifyBaseLogger
		>
	>(async (fastify, options) => {
		const { path = "/graphql", method = ["GET", "POST", "OPTIONS"], ...handlerOptions } = options;

		fastify.route({
			method,
			url: path,
			handler: fastifyApolloHandler<
				Context,
				RawServer,
				RawRequestDefaultExpression<RawServer>,
				RawReplyDefaultExpression<RawServer>
			>(apollo, handlerOptions),
		});
	}, pluginMetadata);
}
